import io.micrometer.core.instrument.*;
import org.springframework.stereotype.Service;

@Service
public class OrderService {
    private final MeterRegistry registry;
    private final Counter ordersPlaced;

    OrderService(MeterRegistry registry) {
        this.registry = registry;
        this.ordersPlaced = Counter.builder("orders.placed")
            .description("Total orders placed successfully")
            .tag("service", "payment")
            .register(registry);
    }

    public String placeOrder(String symbol, int qty, double price) {
        try {
            if (qty <= 0) throw new IllegalArgumentException("Invalid qty");
            // ... save order
            ordersPlaced.increment();
            return "ORD-" + System.currentTimeMillis();
        } catch (IllegalArgumentException e) {
            // Tag added at increment time:
            registry.counter("orders.failed", "reason", "validation").increment();
            throw e;
        } catch (Exception e) {
            registry.counter("orders.failed", "reason", "system").increment();
            throw e;
        }
    }
}

