import io.micrometer.core.instrument.*;
import org.springframework.stereotype.Service;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.*;

@Service
public class PaymentQueueService {
    private final Queue<String> queue = new java.util.concurrent.LinkedBlockingQueue<>();
    private final AtomicInteger pendingCount;

    PaymentQueueService(MeterRegistry registry) {
        // AtomicInteger registered as a Gauge:
        pendingCount = registry.gauge(
            "payments.pending",
            new AtomicInteger(0));
    }

    public void enqueue(String paymentId) {
        queue.add(paymentId);
        pendingCount.incrementAndGet();
        System.out.println("Enqueued " + paymentId + " (pending: " + pendingCount.get() + ")");
    }

    public String dequeue() {
        String paymentId = queue.poll();
        if (paymentId != null) {
            pendingCount.decrementAndGet();
            System.out.println("Dequeued " + paymentId + " (pending: " + pendingCount.get() + ")");
        }
        return paymentId;
    }

    public int getPendingCount() { return pendingCount.get(); }
}

