import io.micrometer.core.instrument.*;
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class DatabaseService {
    private final MeterRegistry registry;
    private final Timer findByIdTimer;

    DatabaseService(MeterRegistry registry) {
        this.registry = registry;
        findByIdTimer = Timer.builder("db.query.duration")
            .description("DB query execution time")
            .tag("query", "findById")
            .register(registry);
    }

    // Wraps the operation and records duration:
    public Optional<String> findById(String id) {
        return findByIdTimer.record(() -> {
            // Simulate DB query:
            try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            return Optional.of("Product: " + id);
        });
    }

    // Manual start/stop for complex operations:
    public List<String> findAll() {
        Timer.Sample sample = Timer.start(registry);
        try {
            // Simulate longer DB scan:
            try { Thread.sleep(100); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            return List.of("Product A", "Product B");
        } finally {
            sample.stop(Timer.builder("db.query.duration")
                .tag("query", "findAll")
                .register(registry));
        }
    }

    public void printStats() {
        System.out.printf("findById: count=%d total=%.0fms%n",
            (long) findByIdTimer.count(),
            findByIdTimer.totalTime(java.util.concurrent.TimeUnit.MILLISECONDS));
    }
}

