import org.springframework.boot.actuate.health.*;
import org.springframework.stereotype.Component;

interface StockFeedClient { boolean isConnected(); long getLatencyMs(); }

@Component
public class StockFeedHealthIndicator implements HealthIndicator {
    private final StockFeedClient client;
    StockFeedHealthIndicator(StockFeedClient c) { client = c; }

    @Override
    public Health health() {
        if (!client.isConnected()) {
            return Health.down()
                .withDetail("reason", "Stock feed disconnected")
                .build();
        }
        long latency = client.getLatencyMs();
        if (latency > 500) {
            return Health.unknown()
                .withDetail("latencyMs", latency)
                .withDetail("warning", "High latency — degraded performance")
                .build();
        }
        return Health.up().withDetail("latencyMs", latency).build();
    }
}

