import org.springframework.boot.actuate.health.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;
import java.util.concurrent.atomic.AtomicReference;

@Component
public class CachedExternalApiHealthIndicator implements HealthIndicator {

    // Starts as UNKNOWN — not yet checked:
    private final AtomicReference<Health> cachedHealth =
        new AtomicReference<>(Health.unknown().withDetail("reason", "Initial check pending").build());

    // Run actual check every 30 seconds:
    @Scheduled(fixedRate = 30_000)
    public void refreshHealth() {
        try {
            long latency = pingExternalApi();
            cachedHealth.set(Health.up()
                .withDetail("latencyMs", latency)
                .withDetail("checkedAt", java.time.LocalDateTime.now().toString())
                .build());
        } catch (Exception e) {
            cachedHealth.set(Health.down()
                .withDetail("reason", e.getMessage())
                .withDetail("checkedAt", java.time.LocalDateTime.now().toString())
                .build());
        }
    }

    // Instant — reads cached value:
    @Override
    public Health health() { return cachedHealth.get(); }

    private long pingExternalApi() throws Exception {
        long start = System.currentTimeMillis();
        // HTTP call to external API...
        return System.currentTimeMillis() - start;
    }
}

