// application.properties: management.endpoints.web.exposure.include=health,info,metrics,loggers

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class LoggerLevelTest {
    @Autowired TestRestTemplate rest;

    @Test
    void changeLogLevel_codequest_toDebug() {
        String loggerPath = "/actuator/loggers/com.codequest";

        // GET current level:
        ResponseEntity<String> getResp = rest.getForEntity(loggerPath, String.class);
        assertEquals(HttpStatus.OK, getResp.getStatusCode());
        System.out.println("Before: " + getResp.getBody());

        // POST new level:
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        HttpEntity<Map<String,String>> req = new HttpEntity<>(Map.of("configuredLevel", "DEBUG"), headers);
        ResponseEntity<Void> postResp = rest.postForEntity(loggerPath, req, Void.class);
        assertEquals(HttpStatus.NO_CONTENT, postResp.getStatusCode());

        // Verify changed:
        ResponseEntity<String> afterResp = rest.getForEntity(loggerPath, String.class);
        assertTrue(afterResp.getBody().contains("DEBUG"), "Level should be DEBUG");

        // Reset to INFO:
        rest.postForEntity(loggerPath,
            new HttpEntity<>(Map.of("configuredLevel", "INFO"), headers), Void.class);
    }
}

