@Component
class PaymentMetrics {
    final Counter processed, failed;
    final AtomicInteger queued;
    final Timer processingTimer;
    PaymentMetrics(MeterRegistry r) {
        processed = Counter.builder("payments.processed").register(r);
        failed    = Counter.builder("payments.failed").register(r);
        queued    = r.gauge("payments.queued", new AtomicInteger(0));
        processingTimer = Timer.builder("payment.processing.duration").register(r);
    }
}

@Service
class PaymentService {
    private final PaymentMetrics metrics;
    PaymentService(PaymentMetrics m) { metrics = m; }
    public String process(String orderId) {
        metrics.queued.incrementAndGet();
        return metrics.processingTimer.record(() -> {
            try {
                Thread.sleep(50);
                metrics.processed.increment();
                return "PAY-" + orderId;
            } catch (Exception e) {
                metrics.failed.increment();
                throw new RuntimeException(e);
            } finally {
                metrics.queued.decrementAndGet();
            }
        });
    }
}

