import org.springframework.boot.actuate.health.*;
import io.micrometer.core.instrument.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.*;
import java.util.concurrent.atomic.*;

@Component
class MarketFeedHealthIndicator implements HealthIndicator {
    private final AtomicReference<Health> cache =
        new AtomicReference<>(Health.unknown().withDetail("status","initializing").build());
    @Scheduled(fixedRate=30_000)
    public void refresh() {
        try { long ms=45L; cache.set(Health.up().withDetail("latencyMs",ms).build()); }
        catch(Exception e) { cache.set(Health.down().withDetail("error",e.getMessage()).build()); }
    }
    @Override public Health health() { return cache.get(); }
}

@Component
class TradingMetrics {
    final Counter tradesExecuted;
    final Timer executionTimer;
    final AtomicInteger openPositions;
    TradingMetrics(MeterRegistry r){
        tradesExecuted = Counter.builder("trades.executed").register(r);
        executionTimer = Timer.builder("trade.execution.duration").register(r);
        openPositions  = r.gauge("positions.open", new AtomicInteger(0));
    }
}

@Service
class TradingService {
    private final TradingMetrics m;
    TradingService(TradingMetrics m) { this.m=m; }
    public String executeTrade(String symbol, int qty) {
        m.openPositions.incrementAndGet();
        return m.executionTimer.record(() -> {
            try {
                m.tradesExecuted.increment();
                return "TRD-" + symbol + "-" + qty;
            } finally { m.openPositions.decrementAndGet(); }
        });
    }
}

